```c
#include <stdio.h>

int main() {
    int p, y;
    scanf("%d %d", &p, &y);

    int ans = -1;

    for (int j = y; j > p; j--) {
        int i = 2;
        int d = j;
        while (i * i <= j) {
            if (j % i == 0) {
                d = i;
                break;
            }
            i++;
        }

        if (d > p) {
            ans = j;
            break;
        }
    }

    printf("%d\n", ans);
    return 0;
}
